import {
  type DNSRecord,
  DNSTable,
} from "@/components/vercel-platform/src/blocks/dns-table";

const records: DNSRecord[] = [
  {
    type: "A",
    name: "example.com",
    value: "93.184.216.34",
  },
  {
    type: "AAAA",
    name: "example.com",
    value: "2606:2800:220:1:248:1893:25c8:1946",
    ttl: "3600",
  },
  {
    type: "CNAME",
    name: "www",
    value: "example.com",
    ttl: "300",
  },
  {
    type: "MX",
    name: "example.com",
    value: "10 mail.example.com.",
    ttl: "600",
  },
  {
    type: "NS",
    name: "example.com",
    value: "ns1.dnsprovider.com.",
    ttl: "86400",
